ValidationRule.errorConditionFormula:
AND(
    NOT(
        OR(
            AND(
                NOT(ISBLANK(TEXT( InquiryType3__c ))),
                NOT(ISBLANK( Date3__c )),
                LEN ( URL3__c ) > 0
            ),
            AND(
                ISBLANK(TEXT( InquiryType3__c )),
                ISBLANK( Date3__c  ),
                LEN ( URL3__c ) = 0
            )
        )
    ),
    NOT(
        OR(
            $Profile.Name = 'システム管理者',
            $Profile.Name = 'データ移行管理者'
        )
    )
)
